   * P2-⑦ 确定性 snip 降级压缩（无需 LLM，无客户端 / 摘要失败时使用）。
   *
   * 按完整对话轮次保留：assistant 的 tool_calls 与后续所有 tool 结果消息会被
   * 同一条 round 包住，避免被截断导致 API 报 400。
   */
  private truncateCompact(sys: ChatMessage, rest: ChatMessage[]): void {
    const rounds = this.splitIntoRounds(rest);
    const keepRounds = this.keepRecentRounds;
    const budget = this.maxTokens * 0.8;

    // 前 (rounds.length - keepRounds) 个 round 是"较旧半区"，对其中长消息做 snip
    const oldRounds = rounds.slice(0, Math.max(0, rounds.length - keepRounds));
    const oldEndIndex = oldRounds.reduce((sum, r) => sum + r.length, 0);

    const snipped = rest.map((msg, i) => {
      if (i >= oldEndIndex) return msg; // 最近完整轮次保留不动
      const content = msg.content ?? '';
      if (estimateTokens(content) <= SNIP_MSG_TOKEN_THRESHOLD) return msg;
      return { ...msg, content: snipText(content) };
    });

    const snippedTotal = snipped.reduce((sum, m) => sum + estimateMessageTokens(m), 0);
    if (snippedTotal < budget) {
      this.messages = [sys, ...snipped];
      return;
    }

    // 第 2 级：snip 后仍超预算 → 硬丢最旧 rounds，保留最近完整轮次
    const keep = snipped.slice(oldEndIndex);
    this.messages = [sys, ...keep];
  }","new_string":"  /**
   * P2-⑦ 确定性 snip 降级压缩（无需 LLM，无客户端 / 摘要失败时使用）。
   *
   * 按完整对话轮次操作，确保 assistant 的 tool_calls 与后续 tool 结果消息
   * 不会被拆散，避免 API 报 400。
   *
   * 两级策略：
   *   第 1 级 — 对较旧轮次中的长消息做中段裁剪（snip），若预算达标则用；
   *   第 2 级 — snip 后仍超预算，直接丢弃较旧轮次，仅保留最近完整轮次。
   */
  private truncateCompact(sys: ChatMessage, rest: ChatMessage[]): void {
    const rounds = this.splitIntoRounds(rest);
    const keepRounds = this.keepRecentRounds;
    const budget = this.maxTokens * 0.8;

    // 将消息分为「较旧轮次」和「最近轮次」两组（按完整轮次切分，不拆散 tool_calls）
    const splitIdx = Math.max(0, rounds.length - keepRounds);
    const oldRounds = rounds.slice(0, splitIdx);
    const recentRounds = rounds.slice(splitIdx);

    // ── 第 1 级：对较旧轮次中的长消息做中段裁剪 ──
    const snippedOld = this.snipLongMessages(oldRounds.flat());
    const recentMessages = recentRounds.flat();
    const allAfterSnip = [...snippedOld, ...recentMessages];

    const totalAfterSnip = allAfterSnip.reduce(
      (sum, m) => sum + estimateMessageTokens(m), 0,
    );

    if (totalAfterSnip < budget) {
      // 第 1 级生效：snip 后预算充足，用裁剪后的完整上下文
      this.messages = [sys, ...allAfterSnip];
      return;
    }

    // ── 第 2 级：snip 后仍超预算 → 硬丢较旧轮次，仅保留最近完整轮次 ──
    this.messages = [sys, ...recentMessages];
  }

  /** 对消息列表中的长内容做中段裁剪，内容较短的消息保留原样 */
  private snipLongMessages(messages: ChatMessage[]): ChatMessage[] {
    return messages.map((msg) => {
      const content = msg.content ?? '';
      if (estimateTokens(content) <= SNIP_MSG_TOKEN_THRESHOLD) return msg;
      return { ...msg, content: snipText(content) };
    });
  }"}
